const dotenv = require("dotenv");
dotenv.config({ path: "../.env" });

const mongoose  = require("mongoose");
const Chapter   = require("../models/Chapter");
const Resource  = require("../models/Resource");

// ─────────────────────────────────────────────────────────
// HELPER
// ─────────────────────────────────────────────────────────
const seedChapter = async (chapter, { pyqs, easyMCQ, mediumMCQ, hardMCQ }) => {
  const resources = [];

  pyqs.forEach((q, i) => {
    resources.push({
      chapterId:  chapter._id,
      type:       "pyq",
      title:      q.title || `PYQ Q${i + 1}`,
      question:   q.question,
      answer:     q.answer,
      year:       q.year,
      marks:      q.marks,
      difficulty: q.difficulty,
      order:      i + 1,
    });
  });

  easyMCQ.forEach((q, i) => {
    resources.push({
      chapterId: chapter._id, type: "mcq", testLevel: "easy",
      title: `Easy Q${i + 1}`, order: i + 1,
      mcqQuestion: q.q, mcqOptions: q.opts,
      mcqCorrectIndex: q.ans, mcqExplanation: q.exp,
    });
  });

  mediumMCQ.forEach((q, i) => {
    resources.push({
      chapterId: chapter._id, type: "mcq", testLevel: "medium",
      title: `Medium Q${i + 1}`, order: i + 1,
      mcqQuestion: q.q, mcqOptions: q.opts,
      mcqCorrectIndex: q.ans, mcqExplanation: q.exp,
    });
  });

  hardMCQ.forEach((q, i) => {
    resources.push({
      chapterId: chapter._id, type: "mcq", testLevel: "hard",
      title: `Hard Q${i + 1}`, order: i + 1,
      mcqQuestion: q.q, mcqOptions: q.opts,
      mcqCorrectIndex: q.ans, mcqExplanation: q.exp,
    });
  });

  await Resource.insertMany(resources);
  console.log(`  ✅ ${chapter.title} — ${resources.length} resources`);
};


// ═════════════════════════════════════════════════════════
// CH 1 — RESOURCES AND DEVELOPMENT
// ═════════════════════════════════════════════════════════

const ch1_pyqs = [
  { title:"PYQ 2023", question:"What is a resource? Explain the factors that transform a substance into a resource.", answer:"A resource is anything available in the environment that can be used to satisfy human needs, provided the technology is available and its use is culturally acceptable. Factors transforming a substance into a resource: (1) Utility — the substance must be able to satisfy a need. Iron ore is useless until technology converts it to steel. (2) Technology — technology determines what can be used. Uranium was not a resource until nuclear technology was developed. (3) Cultural acceptance — some substances are not used because of cultural taboos. (4) Time — resources are dynamic; what is not a resource today may become one tomorrow. Example: Petroleum was a nuisance before the internal combustion engine; solar energy was not a resource before photovoltaic technology. Resources are the product of the interaction between nature, technology and human society.", year:2023, marks:3, difficulty:"medium" },
  { title:"PYQ 2023", question:"Distinguish between renewable and non-renewable resources with examples.", answer:"Renewable Resources: (1) Can be renewed or reproduced in a short time through natural processes. (2) Examples: solar energy, wind energy, water, forests, fish. (3) Some renewable resources (like forests, fish) can be exhausted if overused beyond the natural rate of replenishment. (4) Inexhaustible renewable resources (solar, wind) will never run out. Non-renewable Resources: (1) Take millions of years to form — formed by geological processes. (2) Once used, cannot be replenished within a human timescale. (3) Examples: coal, petroleum, natural gas, iron ore, copper. (4) Their rate of consumption far exceeds their rate of formation. (5) Known reserves are finite — will eventually be exhausted. Key distinction: Renewable resources can be sustained if used wisely; non-renewable resources will be depleted regardless.", year:2023, marks:3, difficulty:"easy" },
  { title:"PYQ 2022", question:"What is land use? How has land use changed in India over the decades and why?", answer:"Land use refers to the way land is used — for agriculture, forests, grazing, etc. Land use categories in India: (1) Forests. (2) Land not available for cultivation (barren, waste, roads, buildings). (3) Other uncultivated land (grazing, orchards). (4) Fallow land. (5) Net sown area. Changes over decades: (1) Forest area has declined — due to agricultural expansion, urbanisation and deforestation. (2) Net sown area increased through the 1950s-70s (Green Revolution) but has plateaued. (3) Urban and industrial area has expanded significantly with industrialisation. (4) Fallow land has decreased as pressure on land increases. Reasons for change: Population growth, economic development, industrialisation, urbanisation, and policies promoting agricultural expansion.", year:2022, marks:5, difficulty:"hard" },
  { title:"PYQ 2022", question:"What is soil? Explain the process of soil formation.", answer:"Soil is the topmost layer of the earth's surface capable of supporting plant life. It is a complex mixture of minerals, organic matter, water and air. Soil formation (pedogenesis): (1) Parent rock — soil forms from the weathering of parent rock. Granite, limestone, basalt, sandstone all produce different soils. (2) Climate — temperature and rainfall determine the rate and type of weathering. High rainfall in tropics produces deep, leached soils; dry areas produce thin, mineral-rich soils. (3) Organisms — plants, animals and bacteria break down organic matter, creating humus. Earthworms mix and aerate soil. (4) Relief — slope determines erosion and water drainage. Flat land retains soil; slopes lose it. (5) Time — soil formation takes thousands of years. The key factors are abbreviated as CLORPT: Climate, Organisms, Relief/parent rock, Parent material, Time.", year:2022, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"Classify resources on the basis of origin and explain each type.", answer:"Resources classified by origin: (1) BIOTIC RESOURCES: Obtained from living organisms (biosphere). Examples: forests, fish, animals, birds, insects. They can reproduce and replenish. Subclassification: renewable and non-renewable (e.g., coal is fossilised organic matter — biotic but non-renewable). (2) ABIOTIC RESOURCES: Made of non-living materials. Examples: rocks, minerals, metals, wind, solar energy, water. They do not reproduce but some (like solar/wind) are inexhaustible. Key difference: Biotic resources are connected to life systems; abiotic resources are not. The biosphere includes all biotic resources; the lithosphere and atmosphere include most abiotic resources. Both types can be further classified as renewable or non-renewable depending on their rate of replenishment relative to use.", year:2021, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"What is Agenda 21? How is it relevant to resource management?", answer:"Agenda 21 is a non-binding resolution of the United Nations adopted at the Rio Earth Summit (Rio de Janeiro, June 1992). It is an action plan for achieving sustainable development in the 21st century. Significance: (1) It recognised that unsustainable patterns of production and consumption — mainly in industrialised countries — were destroying the environment. (2) It called for international cooperation to combat environmental degradation. (3) It linked environmental sustainability to economic and social development — poverty was identified as a cause of environmental degradation. (4) It called for 'every locality in the world' to develop a local Agenda 21 to implement sustainable development. Relevance to resource management: Agenda 21 established the principle that resources must be used in ways that do not deplete them for future generations — the core principle of sustainable development.", year:2021, marks:3, difficulty:"medium" },
  { title:"PYQ 2020", question:"Explain resource planning in India. What are its three stages?", answer:"Resource planning is the process of making a judicious use of resources. India needs it because resources are unevenly distributed — some states are mineral-rich but educationally backward; others are educationally advanced but resource-poor. Three stages: (1) IDENTIFICATION AND INVENTORY: Surveying, mapping and measuring the quantity and quality of resources in every region. Includes geological surveys, forest surveys, soil surveys. (2) EVOLVING A PLANNING STRUCTURE: Creating institutions and planning frameworks at national, state and local levels with appropriate technology and skills. (3) MATCHING RESOURCES WITH DEVELOPMENT PLANS: Ensuring that resource use plans fit into the overall national development plan. Resources must be matched with the available technology, financial feasibility and historical/cultural context. Independent India inherited vast resources but faced the challenge of using them for the benefit of all citizens, not just the elite.", year:2020, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"What is sustainable development? How can resource conservation be achieved?", answer:"Sustainable development is development that meets the needs of the present without compromising the ability of future generations to meet their own needs (Brundtland Commission, 1987). Resource conservation methods: (1) Using renewable resources at rates within their replenishment capacity. (2) Technological efficiency — doing more with less; reducing waste. (3) Substitution — replacing non-renewable resources with renewable ones where possible. (4) Recycling — recovering and reusing materials. (5) Policy measures — taxation of resource depletion, protected areas, international agreements. (6) Education and awareness — changing consumption patterns. Indian traditional approaches: (1) Chipko movement — protecting forests. (2) Traditional water harvesting. (3) Sacred groves ('Dev vans') protecting biodiversity. (4) Traditional soil conservation in terraced agriculture.", year:2020, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"Describe the major types of soils found in India.", answer:"India has several major soil types: (1) ALLUVIAL SOIL: Most widespread — found in northern plains, river deltas, coastal plains. Very fertile; good for wheat, rice, sugarcane. Contains khadar (new alluvium, lighter coloured, more fertile) and bhangar (old alluvium). (2) BLACK SOIL (Regur soil): Found in Deccan plateau — Maharashtra, Gujarat, MP. Ideal for cotton (hence 'black cotton soil'). High clay content — swells when wet, cracks when dry. Rich in calcium, potassium. (3) RED AND YELLOW SOIL: Found in low rainfall regions of Deccan, Orissa, Chhattisgarh, Eastern Ghats. Red colour from iron diffusion; yellow when hydrated. (4) LATERITE SOIL: High rainfall tropical regions — Kerala, Karnataka, Maharashtra hills. Formed by intense leaching. Low fertility but suitable for tea, coffee. (5) ARID/DESERT SOIL: Western Rajasthan. Dry, sandy, low humus. Needs irrigation. (6) FOREST SOILS: Mountain regions. Thin, coarse.", year:2019, marks:5, difficulty:"hard" },
  { title:"PYQ 2019", question:"What is soil erosion? Describe the causes and methods of soil conservation.", answer:"Soil erosion is the removal of the topmost fertile layer of soil by natural agents (wind, water) or human activities. Causes: (1) DEFORESTATION — without plant cover, rain directly hits soil and washes it away. (2) OVERGRAZING — animals eat vegetation and compact soil. (3) CONSTRUCTION — building activities expose bare soil. (4) MINING — open-cast mining destroys soil structure. (5) POOR AGRICULTURAL PRACTICES — ploughing up and down slopes, not using contour lines. Types: (1) Sheet erosion — thin layer removed by water. (2) Gully erosion — deep channels cut by water. (3) Wind erosion — in arid areas, wind removes fine particles. Conservation methods: (1) Contour ploughing. (2) Terrace farming. (3) Strip cropping. (4) Shelter belts (windbreaks). (5) Afforestation. (6) Bunding (building small embankments). (7) Controlled grazing.", year:2019, marks:5, difficulty:"hard" },
  { title:"PYQ 2023", question:"What is the difference between individual resources, community resources and national resources?", answer:"(1) INDIVIDUAL RESOURCES: Owned privately by individuals. Examples: plots, houses, plantation land, ponds, cattle. In India, many farmers own their agricultural land as individual resources. (2) COMMUNITY RESOURCES (Common Property Resources): Accessible to all members of a community. Examples: village grazing grounds, threshing floors, public parks, playgrounds, village ponds. They are collectively managed but not privately owned. (3) NATIONAL RESOURCES: Belong to the nation. The Constitution gives the government the right to acquire private property for public purposes. Examples: minerals under the soil, water in rivers, forests, wildlife, land beyond 12 nautical miles (oceanic resources). ALL resources within the political boundaries of India are ultimately national resources. This classification matters because national resources can be regulated; individual resources are protected by property rights; community resources are often unprotected and overexploited.", year:2023, marks:3, difficulty:"medium" },
  { title:"PYQ 2022", question:"Why is equitable distribution of resources important? What happens when resources are over-exploited?", answer:"Importance of equitable distribution: (1) If resources are concentrated in a few hands, social inequality deepens — creating conflict. (2) Equal access to resources (land, water, education) is a precondition for social justice. (3) Unequal resource access has historically been a cause of wars, revolutions and social unrest. (4) The Brundtland Commission linked poverty (caused by unequal distribution) to environmental degradation — poor people overexploit resources for survival. Effects of over-exploitation: (1) Resource depletion — non-renewable resources exhausted. (2) Environmental degradation — soil erosion, water pollution, air pollution, species extinction. (3) Loss of ecological services — forests provide water regulation, climate control, biodiversity. (4) Conflict — over scarce water (Kaveri dispute), forests, minerals. (5) Climate change — overuse of fossil fuels. (6) Intergenerational inequity — future generations deprived. Gandhi's warning: 'The earth has enough for everyone's need but not for everyone's greed.'", year:2022, marks:3, difficulty:"medium" },
  { title:"PYQ 2021", question:"What are the problems associated with the use of land resources in India?", answer:"Problems with land resource use in India: (1) DEGRADATION: Land degradation through soil erosion, waterlogging, salinisation of irrigated land, mining activities. An estimated 130 million hectares of land is degraded in India. (2) LAND HUNGER: With population growth, pressure on agricultural land increases — the average farm size has decreased from 2.5 ha to under 1.5 ha. (3) UNEQUAL DISTRIBUTION: Historical inequalities mean some own large amounts while many are landless. Land reform has been only partially successful. (4) DIVERSION: Agricultural land being diverted to industrial, residential and commercial use. SEZs (Special Economic Zones) have been controversial. (5) WASTELAND: Large areas of wasteland (ravines, waterlogged areas) that need treatment. (6) OVEREXPLOITATION: Overgrazing, excessive cultivation without soil conservation leading to fertility decline. (7) REGIONAL IMBALANCE: Some states have surplus agricultural land; others have extreme shortage.", year:2021, marks:5, difficulty:"hard" },
  { title:"PYQ 2020", question:"Explain the significance of black soil for cotton cultivation in India.", answer:"Black soil (Regur soil) is most suitable for cotton because: (1) CLAY CONTENT: Black soil has 62% clay which retains moisture for a long time — important for cotton which needs a long growing season. (2) SELF-PLOUGHING: The soil cracks in summer — these cracks aerate the soil and allow rainfall to percolate. This is called 'self-ploughing'. (3) CHEMICAL COMPOSITION: Rich in calcium carbonate, magnesium, potash, lime — nutrients cotton needs. (4) TEMPERATURE: The black colour absorbs heat, keeping the soil warm — important for cotton germination. (5) MOISTURE RETENTION: Even in dry summers, black soil retains enough moisture for cotton. Distribution: Deccan plateau — Maharashtra, Gujarat, parts of MP, AP and Karnataka. The area coincides almost exactly with the cotton textile belt of India — no coincidence, the soil shaped the industry.", year:2020, marks:3, difficulty:"medium" },
  { title:"PYQ 2019", question:"What is the difference between potential resources and developed resources? Give examples.", answer:"POTENTIAL RESOURCES: Resources that exist in a region but have not yet been utilised fully. Their full exploitation depends on future technological development or economic feasibility. Examples: (1) India has enormous wind and solar energy potential — much of which remains unexploited. (2) Vast mineral deposits in deep ocean floors. (3) Geothermal energy in volcanic regions. (4) Uranium in some regions not yet mined. DEVELOPED RESOURCES: Resources that have been surveyed for their quantity and quality and are being utilised. They have been developed by technology and financial feasibility. Examples: (1) Petroleum from oil fields. (2) Coal from mines. (3) Hydro-electric power from dams. (4) Agricultural crops from cultivated land. The distinction is important for planning — a country with large potential resources but low development needs to invest in technology and infrastructure to develop those resources for economic benefit.", year:2019, marks:3, difficulty:"medium" },
];

const ch1_easyMCQ = [
  { q:"Biotic resources are obtained from:", opts:["Rocks and minerals","The biosphere — living organisms","Wind and solar energy","Deep ocean floors"], ans:1, exp:"Biotic resources come from living organisms — biosphere. Examples: forests, fish, animals, birds. Abiotic resources are non-living: rocks, minerals, wind, solar energy." },
  { q:"Alluvial soil is most extensively found in:", opts:["Deccan Plateau","Western Rajasthan","Northern plains and river deltas","Eastern Ghats"], ans:2, exp:"Alluvial soil — deposited by rivers — covers the northern plains (Indo-Gangetic plain), coastal plains, and river deltas. It is India's most widespread and fertile soil type." },
  { q:"Black soil is also known as:", opts:["Laterite soil","Regur soil","Khadar","Bhangar"], ans:1, exp:"Black soil is called Regur soil. It is ideal for cotton cultivation because of its high clay content, moisture retention, and self-ploughing property (cracks in summer, aerating the soil)." },
  { q:"The Brundtland Commission defined sustainable development as:", opts:["Development using maximum resources","Development that meets present needs without compromising future generations' ability to meet their needs","Development only for rich countries","Development that protects only wildlife"], ans:1, exp:"The Brundtland Commission (1987 report 'Our Common Future') defined sustainable development as 'development that meets the needs of the present without compromising the ability of future generations to meet their own needs' — the standard definition." },
  { q:"Agenda 21 was adopted at which conference?", opts:["Stockholm Conference 1972","Kyoto Protocol 1997","Rio Earth Summit 1992","Paris Agreement 2015"], ans:2, exp:"Agenda 21 was adopted at the UN Conference on Environment and Development (UNCED) — the Rio Earth Summit — in Rio de Janeiro, Brazil in June 1992. It is a non-binding action plan for sustainable development." },
  { q:"Laterite soil is found mainly in:", opts:["Northern plains","Western Rajasthan","High rainfall regions like Kerala and Karnataka hills","Black cotton soil belt"], ans:2, exp:"Laterite soil forms in high-temperature, high-rainfall tropical regions through intense leaching (minerals washed deep into soil). Found in Kerala, Karnataka, Tamil Nadu hills, Assam. Suitable for tea and coffee but low in fertility." },
  { q:"Khadar is:", opts:["Old alluvium — higher, darker","New alluvium — lighter coloured, more fertile, found in floodplains","Black soil type","Desert soil type"], ans:1, exp:"Khadar is new alluvium — lighter coloured, more fertile, found in the lower floodplains and renewed by annual flooding. Bhangar is old alluvium — higher ground, darker, less frequently flooded and renewed." },
  { q:"Resources owned by the community and accessible to all its members are called:", opts:["Individual resources","National resources","Community resources (common property resources)","International resources"], ans:2, exp:"Community resources (common property resources) include village grazing grounds, public parks, ponds — owned collectively rather than privately. They are different from individual resources (privately owned) and national resources (owned by the state)." },
  { q:"The process of replenishing soil nutrients through natural or farming methods is called:", opts:["Soil erosion","Soil conservation","Soil fertility restoration","Soil degradation"], ans:2, exp:"Soil fertility restoration includes: adding organic matter (compost, manure), crop rotation, fallowing (leaving land uncultivated), and adding chemical fertilisers. Maintaining soil fertility is essential for sustainable agriculture." },
  { q:"Which type of soil is best for cotton cultivation?", opts:["Alluvial soil","Laterite soil","Black soil (Regur)","Red soil"], ans:2, exp:"Black soil (Regur) is ideal for cotton — its high clay content retains moisture, it is rich in calcium and magnesium, and it self-ploughs (cracks in summer, aerating the soil). The Deccan cotton belt coincides with the black soil region." },
  { q:"Wind erosion is most severe in:", opts:["Dense forests","Arid and semi-arid regions with sparse vegetation","River floodplains","Coastal areas"], ans:1, exp:"Wind erosion is severe in arid and semi-arid regions (Rajasthan, parts of Gujarat) where vegetation is sparse and soil is loose and dry. Without plant roots to hold soil, wind removes fine particles — creating dust storms and desertification." },
  { q:"Gully erosion creates:", opts:["Flat fertile plains","Deep channels that make land uncultivable — 'badlands' or ravines","Sand dunes","Deltas"], ans:1, exp:"Gully erosion occurs when water cuts deep channels into soil, creating ravines or 'badlands'. The Chambal and Yamuna ravines in UP and MP are classic examples. This land becomes uncultivable." },
  { q:"Which of these is a NON-RENEWABLE resource?", opts:["Solar energy","Wind","Coal","Forest"], ans:2, exp:"Coal takes millions of years to form from compressed organic matter — it cannot be renewed on a human timescale. Solar and wind energy are inexhaustible renewable resources. Forests are renewable if managed sustainably." },
  { q:"The term 'resource' implies:", opts:["Any substance found in nature","A substance that can be utilised by humans using available technology and is culturally acceptable","Only mineral deposits","Only water and soil"], ans:1, exp:"A resource requires: (1) Utility — can meet a human need; (2) Technology — technology exists to exploit it; (3) Cultural acceptance — socially acceptable to use. Without these, a substance is not yet a resource — it is just a material." },
  { q:"Contour ploughing means:", opts:["Ploughing down the slope","Ploughing across the slope following contour lines — prevents water running down and eroding soil","Ploughing only in monsoon season","Ploughing without using animals"], ans:1, exp:"Contour ploughing involves ploughing horizontally across slopes following contour lines, rather than up and down. This creates ridges that slow water flow, reducing runoff and erosion. Each furrow acts as a small dam holding water and soil." },
];

const ch1_mediumMCQ = [
  { q:"Why does India need careful resource planning despite being resource-rich?", opts:["India is not resource-rich","India's resources are more than needed","Resources are unevenly distributed — some states are mineral-rich but technologically backward; others have technology but lack resources. Planning is needed to match resources with developmental capacity","India only has agricultural resources"], ans:2, exp:"India's resource distribution paradox: (1) Jharkhand, Chhattisgarh — mineral-rich but underdeveloped. (2) Kerala — high literacy but resource-poor in minerals. (3) Rajasthan — solar/wind potential but dry. Resource planning ensures these imbalances are addressed and resources used for national benefit." },
  { q:"What is the difference between actual reserves and potential reserves?", opts:["They are the same thing","Actual reserves are surveyed, measured and currently being used; potential reserves are those whose quantity/quality is not fully surveyed or whose exploitation isn't yet technically/economically feasible","Reserves only refer to minerals","Potential reserves are imaginary"], ans:1, exp:"This distinction matters for resource accounting. Actual/developed reserves: surveyed, measured, currently exploited (coal from Jharia mines). Potential reserves: suspected or known to exist but not surveyed or economically exploitable with current technology. India's solar and wind energy are potential reserves of enormous scale — only partially developed." },
  { q:"How does the 'resource curse' (paradox of plenty) work?", opts:["More resources always mean more development","Countries rich in natural resources often have lower economic development than resource-poor countries — because resource revenues reduce incentives for productive investment, create corruption, and cause exchange rate problems that harm other industries","Resources always cause wars","Poor countries have more resources"], ans:1, exp:"The 'resource curse' is a well-documented economic phenomenon: oil-rich countries like Nigeria or Venezuela often develop slower than resource-poor countries like Singapore or South Korea. Reasons: (1) 'Dutch disease' — resource revenues strengthen currency, making manufacturing uncompetitive. (2) Resource revenues create corrupt elite with no incentive for diversification. (3) Revenue volatility from commodity price swings. India avoids this partly by having diverse resources and industries." },
  { q:"Why is soil called a 'living resource'?", opts:["Soil contains rocks which are living","Soil is alive because it contains millions of microorganisms — bacteria, fungi, earthworms — that break down organic matter, cycle nutrients, and maintain fertility. Without these organisms, soil is just dead mineral particles","Soil grows by itself","Soil moves like living things"], ans:1, exp:"Soil is 'living' because of its microbiome: 1 teaspoon of healthy soil contains more microorganisms than there are humans on Earth. These organisms: decompose organic matter, fix nitrogen, cycle phosphorus, create soil structure. When we destroy soil microbiome (through excessive chemicals, compaction), we 'kill' soil. This is why organic farming and soil conservation are about maintaining the living system, not just the mineral content." },
  { q:"What is the significance of the 'sacred grove' (Dev van) tradition for resource conservation?", opts:["Sacred groves are purely religious with no environmental function","Sacred groves are patches of forest protected by religious/cultural taboos — they preserve biodiversity, watershed functions and traditional ecological knowledge. They are an example of traditional resource management that modern conservation can learn from","Sacred groves are only in South India","Sacred groves were always very large"], ans:1, exp:"Sacred groves (Dev vans in Rajasthan, Orans, sacred forests across India) are community-protected forest patches where cutting trees is taboo. They preserve: (1) Biodiversity hotspots. (2) Seed banks for surrounding areas. (3) Water recharge zones. (4) Traditional ecological knowledge. Research has shown many sacred groves contain rare or endemic species. They represent millennia of traditional conservation before modern conservation science." },
  { q:"How did the Green Revolution affect soil quality in India?", opts:["The Green Revolution improved all soil quality","The Green Revolution had no effect on soil","The Green Revolution increased yield through high-yielding seeds, fertilisers and irrigation — but created long-term soil problems: waterlogging and salinisation from over-irrigation, micronutrient depletion from chemical farming, loss of soil biodiversity. Punjab and Haryana show declining yields in some areas from soil exhaustion","The Green Revolution only helped Punjab"], ans:2, exp:"The Green Revolution's soil legacy is complex. Short-term: dramatic yield increases saved millions from famine. Long-term costs: (1) Over-irrigation caused waterlogging in low-lying fields and salinisation as water evaporated leaving salts. (2) Chemical fertilisers gradually depleted micronutrients. (3) Pesticides damaged soil microbiome. (4) Water table depletion. Punjab now faces 'depleting returns' — yields plateauing or falling despite continued inputs." },
  { q:"What is 'shifting cultivation' and why is it environmentally problematic in modern contexts?", opts:["A type of irrigation","A traditional practice where farmers clear forest, cultivate for 2-3 years then move on to allow forest regeneration — sustainable at low population densities but environmentally damaging at high densities when forests cannot recover","A method of soil conservation","Only practised in South India"], ans:1, exp:"Shifting cultivation (jhum in Northeast India, podu in AP) was sustainable for millennia at low population densities — forests recovered in the fallow period. But modern high population pressure means: (1) Fallow periods shortened — forests can't recover. (2) More land cleared annually. (3) Permanent deforestation results. What was once sustainable becomes destructive when population pressure prevents recovery cycles. This shows how resource sustainability depends on intensity of use relative to regeneration capacity." },
  { q:"What does Gandhi's statement 'Earth has enough for everyone's need but not for everyone's greed' mean in the context of resources?", opts:["Gandhi was an economist","Gandhi had no view on resources","It captures the core of sustainable development: resources are sufficient if used at rates meeting genuine human needs; they are insufficient if used at rates driven by unlimited accumulation and conspicuous consumption. The problem is not resource scarcity but unequal and wasteful use — a moral and political problem, not just a technical one","Gandhi meant only food resources"], ans:2, exp:"This is one of Gandhi's most quoted statements because it perfectly captures the resource justice argument. The earth's photosynthetic productivity, soil capacity, and water cycles CAN support 8 billion humans meeting basic needs — but cannot support 8 billion humans consuming at affluent Western patterns. The problem is distribution (inequality) and the nature of consumption (need vs greed), not absolute scarcity. This frames environmental sustainability as a justice issue." },
  { q:"Why is soil erosion described as 'a slow disaster'?", opts:["Soil erosion is not a disaster","Soil erosion happens too slowly to be noticed — it takes hundreds of years to form 1 cm of topsoil but erosion can remove it in years. The damage is cumulative and largely invisible until catastrophic — making it a 'slow disaster' that doesn't receive the attention of sudden floods or earthquakes but has comparable long-term impact","Soil erosion only affects deserts","Soil erosion is easy to reverse"], ans:1, exp:"'Slow disaster' captures soil erosion's temporal paradox. Forming 1 cm of topsoil takes 100-1,000 years; erosion can remove it in months. The damage appears gradually: yields decline slowly over years; land becomes gully-ridden over decades. Because it's slow, it doesn't attract emergency responses — unlike floods. By the time the cumulative damage is visible (ravines, abandoned farmland), restoring soil is enormously expensive and time-consuming. The Indian government estimates 130 million ha of degraded land — representing centuries of accumulated slow disaster." },
  { q:"How does the unequal global distribution of resources relate to international conflicts?", opts:["Resource distribution has no connection to conflict","Resources are evenly distributed globally","Many major conflicts — Gulf Wars (oil), Congo wars (minerals), South China Sea tensions (fisheries, oil) — are fundamentally resource conflicts. Unequal distribution means resource-rich areas become targets for military or economic domination. This is why the UN identifies equitable resource distribution as essential to international peace","Conflicts are only about religion"], ans:2, exp:"Resource-conflict links are well-documented: (1) Oil — Gulf Wars, Libya, conflicts in oil-producing regions. (2) Water — Nile conflicts (Ethiopia/Egypt), Mekong (China/SE Asia), Kaveri dispute (India). (3) Minerals — 'blood diamonds' in West Africa, coltan (Congo) for electronics. (4) Land — most historical wars ultimately about controlling territory and its resources. Climate change predictions suggest increasing resource conflicts over water and arable land. Understanding resources as a cause of conflict is essential for geopolitics." },
  { q:"What is the difference between stock resources and reserve resources?", opts:["They are the same","Stock includes all known resources regardless of technology feasibility; reserves are the portion of stock that can be exploited economically and legally with available technology","Stocks are only minerals","Reserves are only water"], ans:1, exp:"This distinction is crucial for resource economics. Stock: all resources identified — including those not yet technically or economically exploitable. Reserve: the subset of stock that is exploitable with current technology at current prices. Example: Vast coal deposits under the sea floor are stock but not reserves. When technology improves or prices rise, some stock becomes reserve. This is why 'running out' predictions often fail — new technology or higher prices constantly convert stock to reserves." },
  { q:"Why is rain water harvesting called a 'traditional wisdom' that is now being revived?", opts:["Rainwater harvesting was invented recently","Rainwater harvesting — collecting and storing monsoon rain for later use (tanks, ponds, khadins, johads) — is a millennia-old Indian tradition that had been neglected after modern irrigation infrastructure was built, but is being revived as groundwater depletion makes traditional methods essential again","Rainwater harvesting is only for cities","Rainwater harvesting is not used in India"], ans:1, exp:"Traditional rainwater harvesting systems — khadins in Rajasthan, johads in Haryana, bamboo drip irrigation in Meghalaya, tanks in Tamil Nadu — represented sophisticated engineering. Colonial policies that provided canals and wells made these seem obsolete. As groundwater depletion accelerates (Punjab, Rajasthan) and dams face capacity limits, traditional systems are being rediscovered and scientifically validated. Anna Hazare's Ralegan Siddhi watershed revival is a famous modern example." },
  { q:"What are the environmental consequences of mining for resource extraction?", opts:["Mining has no environmental consequences","Mining is entirely beneficial","Mining causes: land degradation and loss of agricultural/forest land; water table depletion; water and soil pollution from mining effluents; dust and air pollution; destruction of biodiversity; displacement of communities. Open-cast mining is particularly damaging — Chhattisgarh, Jharkhand, Orissa show severe environmental degradation in mining areas","Mining only affects underground environments"], ans:2, exp:"Mining's environmental costs are enormous but often ignored in economic calculations. Open-cast coal mining in Jharkhand and Chhattisgarh: deforests vast areas, contaminates water with acid mine drainage, destroys farmland, and displaces Adivasi communities. Iron ore mining in Goa (before partial restrictions) destroyed forests and polluted rivers. The environmental costs of mining are 'externalities' — not paid by mining companies but borne by local communities and future generations." },
  { q:"How does population growth affect resource availability and use?", opts:["Population growth has no effect on resources","More people means more resources through more labour","Population growth increases demand for all resources — food, water, energy, land — while often reducing per-capita resource availability. More people means more soil erosion, more deforestation, more groundwater extraction. Demographic pressure is one of the key drivers of resource depletion, particularly in developing countries","Population growth always leads to resource crisis"], ans:2, exp:"The population-resource relationship is complex (not simply Malthusian): (1) More people need more food → more land under cultivation → more soil erosion, deforestation. (2) More people need more water → groundwater depletion. (3) More people need more energy → more fossil fuel use. (4) But more people also mean more labour and innovation. India's challenge: 18% of world's population on 2.4% of world's land with 4% of world's freshwater — the arithmetic of population-resource pressure is severe." },
  { q:"ASSERTION: Resources are not fixed — what is a resource changes with technology and social values. REASON: Uranium was not a resource before nuclear technology; solar energy was not a resource before photovoltaic technology.", opts:["Both A and R true; R explains with examples why resources are dynamic","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. Resources are dynamic, not static — they are defined by the interaction of technology, economy and social values with the physical world. Historical examples abound: coal was not a resource before steam engines; petroleum was a nuisance before the internal combustion engine; deep ocean minerals are potential resources waiting for the technology that makes extraction economically viable. This is why 'running out of resources' predictions must be made carefully — technology constantly creates new resources." },
];

const ch1_hardMCQ = [
  { q:"ASSERTION: Sustainable development is fundamentally a political challenge, not a technical one.\nREASON: The technology for sustainable energy, agriculture and manufacturing largely exists — the barrier is distributing costs and benefits equitably across nations, classes and generations.", opts:["Both A and R true; R correctly identifies the political nature of sustainability","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. Solar panels, electric vehicles, organic farming, and sustainable forestry exist as technologies. The barriers to their universal adoption are political-economic: (1) Fossil fuel industries resist change. (2) Rich countries have benefited from unsustainable industrialisation and resist bearing disproportionate transition costs. (3) Poor countries argue they should not be denied the development path rich countries used. Solving sustainability requires political agreements on burden-sharing — far harder than technical innovation." },
  { q:"CASE-BASED: Jharkhand is mineral-rich (coal, iron ore, mica) but ranks among India's poorest states. How does this illustrate the 'resource curse' and what would resource planning need to address?", opts:["Jharkhand's poverty disproves the resource curse","Jharkhand's richness causes its poverty — all mining states are wealthy","Jharkhand illustrates the resource curse: mineral extraction creates enclave wealth that doesn't integrate with local economy; tribal displacement destroys traditional livelihoods; environmental degradation reduces agricultural productivity; resource revenues attract corrupt interests. Resource planning must address tribal rights, environmental rehabilitation, value addition to raw materials (steel from iron ore, power from coal), and ensuring revenues fund local development","Jharkhand just needs more mining"], ans:2, exp:"Jharkhand is the textbook Indian case of the resource curse. It produces 25% of India's minerals but has 36% poverty rate. Why: (1) Most minerals exported as raw material — value added elsewhere. (2) Mining companies are national/multinational — profits leave the state. (3) Adivasi communities are displaced without adequate compensation. (4) Environmental degradation harms agriculture and health. (5) Revenue captured by political elite. Resource planning for Jharkhand must address these equity and sustainability issues, not just extraction volumes." },
  { q:"EXTRACT-BASED: 'The problem of resource depletion is not that resources are running out — it is that the wrong people are using too much of them.' Evaluate.", opts:["Resources are objectively running out","Consumption is equally distributed globally","The statement captures the inequality dimension of resource depletion: the world's richest 20% consume 80% of global resources. The USA with 4% of world population uses 25% of its resources. If all 8 billion humans consumed at American rates, we would need 4-5 Earths. The problem is simultaneously absolute (some resources like aquifers ARE depleting) AND distributional (consumption inequality is the primary driver). Both dimensions must be addressed","Consumption inequality is not a problem"], ans:2, exp:"This is the equity dimension of sustainability. The arithmetic is stark: 1 American consumes roughly 32 times more resources than 1 Indian; 1 European about 12 times more than 1 African. If development means reaching American consumption levels, we need multiple planets. The statement is substantially true — but not entirely: some resources (groundwater in North China Plain, Punjab) are depleting even under current consumption patterns. The solution requires both reducing consumption in rich countries AND enabling human development in poor ones through efficient technology." },
  { q:"CASE-BASED: A state government proposes to convert a large tract of forest land to agricultural land to feed its growing population. Evaluate this decision from a resource management perspective.", opts:["This is always the right decision","Forest conversion is always wrong","The decision involves multiple resource trade-offs: Gains — more food production for present population. Costs — (1) Forest ecosystem services (carbon storage, water regulation, biodiversity, soil stability) are worth far more economically than the agricultural value of the land. (2) Deforestation causes soil erosion, flooding and reduced rainfall. (3) Biodiversity loss is irreversible. (4) Carbon emissions accelerate climate change which threatens future food production. Sound resource management would suggest intensifying productivity on existing agricultural land, restoring degraded land, and protecting remaining forests whose ecosystem services are the foundation of long-term food security","Forest conversion has no costs"], ans:2, exp:"This tests understanding of ecosystem services and long-term resource management. Forest ecosystem services (water regulation, carbon storage, erosion prevention, biodiversity) have been calculated to be worth far more than the direct economic value of converting to agriculture. The Millennium Ecosystem Assessment showed that most ecosystem services are declining globally, and their loss reduces long-term agricultural productivity. Short-term food production gain from forest conversion typically leads to long-term loss through erosion, flooding and climate impacts." },
  { q:"ASSERTION: The classification of resources into individual, community and national is ultimately a political-legal construct, not a natural one.\nREASON: The same physical substance (a river, a mountain, a forest) is simultaneously 'natural', 'national', 'communal' and in some ways 'individual' — the classification depends on legal frameworks that change over time and across cultures.", opts:["Both A and R true; R correctly explains the political-legal nature of resource classification","Both true but unconnected","A true, R false","A false, R true"], ans:0, exp:"Both correct. The Narmada River illustrates: its water is 'national' (the state can dam it); 'communal' (fishing communities have traditional use rights); 'individual' (private landowners along its banks); and 'natural' (it exists independent of legal categories). Which category dominates is determined by law — and law reflects power. When dams displace tribal communities, it asserts 'national' resource rights over 'communal' ones. Resource classification is therefore always political — it determines who benefits and who bears costs." },
  { q:"How does the concept of 'intergenerational equity' challenge standard economic practice in resource valuation?", opts:["Intergenerational equity is not an economic concept","Standard economics already accounts for future generations","Standard economics uses 'discounting' — future benefits are valued less than present ones. This means resources preserved for future generations are valued very low today. Intergenerational equity challenges this: if future people have equal moral worth to present people, their needs should not be 'discounted'. This implies resources should be preserved at much higher rates than economic calculations suggest — effectively requiring a political rather than purely market approach to resource management","Economics and equity are unrelated"], ans:2, exp:"The discount rate problem is fundamental to sustainable development economics. Standard economics discounts future values — $1 received in 100 years is worth almost nothing today at a 5% discount rate. This means any resource that takes more than 50-100 years to regenerate gets almost zero economic weight for future generations. Climate change cost-benefit analyses show radically different results depending on discount rates used. Intergenerational equity — treating future generations' welfare equally to present — cannot be achieved through market mechanisms that systematically discount the future; it requires political commitments." },
  { q:"CASE-BASED: Traditional Rajasthani farmers developed the 'khadin' system — earthen embankments that retain runoff for agriculture in an arid environment. What does this system reveal about the relationship between traditional knowledge, resource management and modern sustainability?", opts:["Traditional systems are always inferior to modern ones","Traditional systems have nothing to teach modern resource management","Khadins represent sophisticated understanding of: hydrology (how water flows in semi-arid landscapes), soil science (retained silt enhances fertility), and community governance (collectively maintained). They demonstrate: (1) Sustainable resource management doesn't require modern science — traditional ecological knowledge is evidence-based through generations of observation. (2) Modern sustainability can learn from traditional systems. (3) Colonial policies that replaced traditional systems with 'modern' irrigation often created more problems. Integrating traditional and modern knowledge is the most promising approach","Traditional knowledge is scientifically proven worthless"], ans:2, exp:"Khadins are an extraordinary example. Built centuries ago by Rajput farmers in hyperarid western Rajasthan (50-200mm rainfall), they capture monsoon runoff and use it for rabi (winter) crops — achieving 'dry farming' in conditions where conventional wisdom says agriculture is impossible. Modern hydrological surveys have validated their design principles. Anna Hazare's Ralegan Siddhi, Rajendra Singh's water harvesting work in Alwar — all revive traditional systems. The lesson: 'scientific' colonial resource management that replaced these systems with tube wells has led to groundwater depletion that traditional systems prevented." },
  { q:"ASSERTION: India's approach to resource management must balance sovereignty (right to exploit its own resources) with global responsibility (environmental obligations).\nREASON: India has vast coal reserves and the right to use them for development, but coal burning is the largest source of CO2 emissions — creating tension between national development and global climate responsibility.", opts:["Both A and R true; R correctly identifies the specific tension","Both true but unconnected","A true, R overstates — India's emissions are low","A false, R true"], ans:0, exp:"Both correct. This is the central tension in climate negotiations. India's position: (1) It has the sovereign right to develop; (2) Historical emissions are dominated by rich countries; (3) Per-capita Indian emissions are far below rich countries. Yet India is now the 3rd largest absolute emitter. The tension: India using coal for development replicates the path that created climate change; renewable energy is increasingly competitive but requires upfront investment. International agreements (Paris) require India to limit emissions while financing development differently — a genuine sovereignty vs global responsibility tension." },
  { q:"EXTRACT: 'Soil is perhaps the most undervalued natural resource, yet no civilisation has survived the destruction of its soil.' Evaluate with evidence.", opts:["Soil is not important for civilisations","Civilisations have survived soil destruction","The historical evidence is compelling: (1) The Fertile Crescent (Mesopotamia) — once the world's most productive agricultural region, now largely desert/degraded due to millennia of irrigation-induced salinisation. (2) Dust Bowl (USA 1930s) — poor farming practices on Great Plains destroyed topsoil, forced mass migration. (3) Easter Island — soil depletion through deforestation contributed to civilisational collapse. India's Indus Valley civilisation is partly attributed declining to climate-induced soil changes. Modern soil loss (26 billion tonnes annually globally) threatens agricultural foundations. The historical evidence strongly supports the claim.","Soil can always be restored quickly"], ans:2, exp:"Both the historical and contemporary evidence support the claim. The Mesopotamian case is particularly instructive: ancient Sumer was so productive it supported the world's first cities — but millennia of irrigation without drainage caused salt to accumulate in soils. By 1000 BCE, wheat was replaced by more salt-tolerant barley; by 1700 BCE, even barley couldn't grow in much of the region. A civilisation destroyed not by war but by soil salinisation. The Dust Bowl forced 3.5 million Americans to migrate in the 1930s — a demographic catastrophe from soil mismanagement. India's 130 million ha of degraded land is a slow-motion version of these historical warnings." },
  { q:"CASE-BASED: A mining company argues that iron ore extraction in a tribal area will bring 'development'. Tribal communities argue it will destroy their 'forest-based resource economy'. Who has the stronger argument and why?", opts:["The mining company is always right","Tribal communities are always right","The tribal argument is often stronger in the long run: Forest-based economies provide: food (fruits, nuts, honey), medicine, building materials, water regulation, and livelihood for millions sustainably. Mining: destroys forests (irreversible in the short run), depletes local water tables, creates temporary employment (mines eventually close), concentrates profits outside the community. The Forest Rights Act (2006) and PESA (1996) recognise tribal communities' rights over forest resources. The strongest position recognises both: development is needed but must be achieved with tribal consent, adequate compensation, environmental rehabilitation, and equitable benefit-sharing","Development never conflicts with tribal rights"], ans:2, exp:"This reflects a real and ongoing conflict in India. The tribal case is supported by: (1) Long-term sustainability — forest economies are self-renewing; mining depletes and ends. (2) Community welfare — tribal communities depend on forest ecosystem services that mining destroys. (3) Legal rights — PESA (1996) and Forest Rights Act (2006) give tribal communities rights over forest resources. (4) Historical evidence — tribal communities in mining regions (Jharkhand, Chhattisgarh) have not benefited economically from minerals extracted from their land. The solution is not mining vs no mining but ensuring tribal rights, environmental protection, and equitable benefit-sharing are central to any extraction." },
  { q:"ASSERTION: The 'commons' (community resources) are inherently prone to over-exploitation.\nREASON: Without private ownership or state regulation, individual users have incentive to use as much as possible before others do — the 'tragedy of the commons' (Garrett Hardin).", opts:["Both A and R true — commons always collapse","A is false — commons can be sustainably managed through community governance; R correctly describes one model but not the only outcome","A true, R false","Both false"], ans:1, exp:"This is one of the most important nuances in resource management. Hardin's 'tragedy of the commons' (1968) is influential but partially wrong. Nobel economist Elinor Ostrom (2009) showed empirically that communities around the world (Swiss Alpine pastures, Japanese forests, Spanish irrigation systems) have successfully managed commons for centuries without privatisation or state regulation — through community governance rules. The tragedy occurs when communities are DISRUPTED (by colonialism, market penetration, or population pressure) not as an inevitable outcome of common ownership. India's village commons worked sustainably until colonial privatisation disrupted them." },
  { q:"How does climate change challenge traditional approaches to resource planning?", opts:["Climate change has no effect on resource planning","Resource planning can ignore climate change","Climate change makes resource planning much harder: (1) Water availability is changing — some areas getting more rain, others less; glacial melt changes river regimes. (2) Agricultural zones are shifting. (3) Extreme events (floods, droughts) are more frequent. (4) Resources that were stable (seasonal rivers, groundwater recharge rates) are becoming variable and unpredictable. Traditional planning assumes stable resource availability; climate change requires planning for increased variability and uncertainty — including 'climate proofing' infrastructure and building resilience into resource systems","Climate change only affects coastal areas"], ans:2, exp:"Climate change fundamentally disrupts resource planning because it makes the future unlike the past. Traditional planning used historical averages — average rainfall, average glacier melt, average river flows. Climate change means these averages are changing and variability is increasing. India-specific challenges: (1) Himalayan glacier retreat threatens long-term river flows (Ganga, Indus, Brahmaputra). (2) Monsoon patterns are changing — some areas getting more intense but shorter rainfall; others drying. (3) Sea level rise threatens coastal agricultural land. Resource planners must now account for uncertainty ranges rather than historical averages." },
  { q:"CASE-BASED: The 'payment for ecosystem services' (PES) model proposes paying forest communities to maintain forests that provide services to downstream users (clean water, flood control). Evaluate this as a resource management approach.", opts:["PES is the perfect solution to all environmental problems","PES is not a valid concept","PES has significant strengths and weaknesses. Strengths: (1) Gives economic value to ecosystem services previously treated as free. (2) Creates financial incentives for conservation. (3) Can support forest community livelihoods. Weaknesses: (1) Commodifying nature can create perverse incentives. (2) Who determines the 'right' price for ecosystem services? (3) Poor communities may sell conservation rights cheaply under economic pressure. (4) Does not address the root cause (unsustainable consumption). PES works best as one tool among many — combined with legal rights, community governance, and consumption reduction","PES has no weaknesses"], ans:2, exp:"PES schemes have produced mixed results globally. Costa Rica's national PES programme successfully reduced deforestation — one of the most cited successes. But: (1) Studies show some Costa Rican payments went to forests that weren't going to be cut anyway (additionality problem). (2) In South Africa, invasive species removal PES worked well because of clear additionality. (3) In India, joint forest management schemes with tribal communities have had variable success depending on community rights and benefit-sharing. The framework is useful but must be designed carefully to avoid exploitation of poor communities and greenwashing by corporations." },
];


