// ═════════════════════════════════════════════════════════
// MAIN SEED FUNCTION
// ═════════════════════════════════════════════════════════

const seedGeography = async () => {
  try {
    await mongoose.connect(process.env.MONGO_URI);
    console.log("✅ Connected to MongoDB");

    const slugs = [
      "resources-and-development",
      "forest-and-wildlife-resources",
      "water-resources",
      "minerals-and-energy-resources",
      "manufacturing-industries",
      "lifelines-of-national-economy",
      "agriculture",
    ];

    const chapters = await Chapter.find({ slug: { $in: slugs } });
    if (!chapters.length) {
      console.error("❌ Chapters not found. Run main seed.js first.");
      process.exit(1);
    }
    console.log(`📚 Found ${chapters.length} chapters`);

    const map = {};
    chapters.forEach((c) => { map[c.slug] = c; });

    const chapterIds = chapters.map((c) => c._id);
    await Resource.deleteMany({ chapterId: { $in: chapterIds } });
    console.log("🗑️  Cleared old resources");

    const chaptersData = [
      { slug: "resources-and-development",   pyqs: ch1_pyqs, easyMCQ: ch1_easyMCQ, mediumMCQ: ch1_mediumMCQ, hardMCQ: ch1_hardMCQ },
      { slug: "forest-and-wildlife-resources",pyqs: ch2_pyqs, easyMCQ: ch2_easyMCQ, mediumMCQ: ch2_mediumMCQ, hardMCQ: ch2_hardMCQ },
      { slug: "water-resources",              pyqs: ch3_pyqs, easyMCQ: ch3_easyMCQ, mediumMCQ: ch3_mediumMCQ, hardMCQ: ch3_hardMCQ },
      { slug: "agriculture",                   pyqs: ch4_pyqs, easyMCQ: ch4_easyMCQ, mediumMCQ: ch4_mediumMCQ, hardMCQ: ch4_hardMCQ },
      { slug: "minerals-and-energy-resources",pyqs: ch5_pyqs, easyMCQ: ch5_easyMCQ, mediumMCQ: ch5_mediumMCQ, hardMCQ: ch5_hardMCQ },
      { slug: "manufacturing-industries",     pyqs: ch6_pyqs, easyMCQ: ch6_easyMCQ, mediumMCQ: ch6_mediumMCQ, hardMCQ: ch6_hardMCQ },
      { slug: "lifelines-of-national-economy",pyqs: ch7_pyqs, easyMCQ: ch7_easyMCQ, mediumMCQ: ch7_mediumMCQ, hardMCQ: ch7_hardMCQ },
    ];

    let total = 0;
    for (const cd of chaptersData) {
      const ch = map[cd.slug];
      if (!ch) { console.warn(`⚠️  Not found: ${cd.slug}`); continue; }
      await seedChapter(ch, { pyqs: cd.pyqs, easyMCQ: cd.easyMCQ, mediumMCQ: cd.mediumMCQ, hardMCQ: cd.hardMCQ });
      total += cd.pyqs.length + cd.easyMCQ.length + cd.mediumMCQ.length + cd.hardMCQ.length;
    }

    console.log("\n✅ Geography seed complete");
    console.log("──────────────────────────────────────────────");
    console.log(`Chapters : ${chaptersData.length}`);
    console.log(`Total    : ${total} resources (${total/chaptersData.length} per chapter)`);
    console.log("──────────────────────────────────────────────");

    process.exit(0);
  } catch (err) {
    console.error("❌ Seed failed:", err.message);
    process.exit(1);
  }
};

seedGeography();